output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?conflict ?conflictLabel ?warAimLabel ?outcomeLabel WHERE {
  ?conflict wdt:P31 wd:Q23222 .
  ?conflict wdt:P1923 wd:Q810 .
  ?conflict rdfs:label ?conflictLabel .
  FILTER(lang(?conflictLabel) = "en")
  .
  OPTIONAL {
    ?conflict wdt:P1073 ?warAim .
    ?warAim rdfs:label ?warAimLabel .
    FILTER(lang(?warAimLabel) = "en")
  }
  OPTIONAL {
    ?conflict wdt:P1634 ?outcome .
    ?outcome rdfs:label ?outcomeLabel .
    FILTER(lang(?outcomeLabel) = "en")
  }
}

